// TypeScript implementation for Casting with As
interface CastingwithAsPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processCastingwithAs(item: CastingwithAsPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processCastingwithAs({ id: 1, title: 'Casting with As', status: 'active' }));

